/**
 * Get the direct PDF URL for a vocational subject's department
 * @param {string} subjectCode - e.g., "20101-2001"
 * @returns {{ pdfUrl: string, listingUrl: string, deptCode: string } | null}
 */
export function getPdfUrl(subjectCode) {
  if (!subjectCode) return null;
  const deptCode = subjectCode.split('-')[0];
  const isPvs = deptCode.startsWith('3');
  const base = isPvs ? PDF_BASE_PVS : PDF_BASE_PVCH;
  const listingUrl = isPvs ? LISTING_PVS : LISTING_PVCH;
  const groupCode = deptCode.substring(0, 3) + '00';
  
  const filename = PDF_MAP[deptCode];
  if (filename) {
    return {
      pdfUrl: `${base}/${groupCode}/${filename}`,
      listingUrl,
      deptCode,
    };
  }
  
  // Fallback: link to listing page
  return {
    pdfUrl: null,
    listingUrl,
    deptCode,
  };
}

